mapper.select:
SELECT
id, api_id, question, answer, item1, item2, item3, item4,
explains, url, subject, model, question_type
FROM question
WHERE 1=1

    AND subject = #{subject}


    AND UPPER(model) = UPPER(#{model})


    AND question_type = #{questionType}

LIMIT #{limit}

SELECT
    id, api_id, question, answer, item1, item2, item3, item4,
    explains, url, subject, model, question_type
FROM question
WHERE subject = #{subject}
  AND model = #{model}

